/* WM FINAL MENU SAFE v2: açılışta kelime ekranına otomatik geçişi engeller */
(function(){
  window.WM_START_ON_MENU = true;
  window.WM_DISABLE_AUTO_WORD_OPEN = true;
  const bootUntil = Date.now() + 2600;
  const originalShowScreen = window.showScreen;
  if(typeof originalShowScreen === 'function' && !window.__wmShowScreenMenuGuarded){
    window.__wmShowScreenMenuGuarded = true;
    window.showScreen = function(id){
      if(id === 'sc-word' && window.WM_DISABLE_AUTO_WORD_OPEN && Date.now() < bootUntil && !window.__wmUserNavigatedAfterBoot){
        console.log('🛑 Açılışta sc-word engellendi; menüde kalındı.');
        id = 'sc-menu';
      }
      return originalShowScreen.apply(this, arguments.length ? [id].concat([].slice.call(arguments,1)) : arguments);
    };
  }
})();
